-- {"operators": "FULL_OUTER_JOIN,AGGREGATE,CTE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ORDER_LINE", "lakeflow": "gold_stations"}
WITH shipped AS (SELECT OL_W_ID AS wid, OL_D_ID AS did, COUNT(*) AS n_shipped, SUM(OL_AMOUNT) AS rev_out FROM ORDER_LINE GROUP BY OL_W_ID, OL_D_ID), received AS (SELECT OL_SUPPLY_W_ID AS wid, OL_D_ID AS did, COUNT(*) AS n_received, SUM(OL_AMOUNT) AS rev_in FROM ORDER_LINE GROUP BY OL_SUPPLY_W_ID, OL_D_ID) SELECT COALESCE(s.wid, r.wid) AS w_id, COALESCE(s.did, r.did) AS d_id, s.n_shipped, r.n_received, COALESCE(s.rev_out, 0) + COALESCE(r.rev_in, 0) AS total_revenue FROM shipped s FULL OUTER JOIN received r ON s.wid = r.wid AND s.did = r.did
